var whiteboard = new Whiteboard("WB-001", 2.0, 1.5);
Assert.That(whiteboard.Id, Is.EqualTo("WB-001"));
Assert.That(whiteboard.Width, Is.EqualTo(2.0));
Assert.That(whiteboard.Height, Is.EqualTo(1.5));

var learningSpace = new LearningSpace("LS-001", 10.0, 8.0);
var whiteboard = new Whiteboard("WB-001", 2.0, 1.5);
bool fits = learningSpace.CanFit(whiteboard);
Assert.That(fits, Is.True);

var learningSpace = new LearningSpace("LS-001", 10.0, 8.0);
var whiteboard = new Whiteboard("WB-001", 12.0, 1.5);
bool fits = learningSpace.CanFit(whiteboard);
Assert.That(fits, Is.False);

var mockRepo = new Mock<IWhiteboardRepository>();
var mockLsRepo = new Mock<ILearningSpaceRepository>();
var service = new WhiteboardService(mockRepo.Object, mockLsRepo.Object);

var result = await service.CreateWhiteboardAsync("WB-001", 2.0, 1.5, "LS-001");

Assert.That(result.IsSuccess, Is.True);
mockRepo.Verify(r => r.AddAsync(It.IsAny<Whiteboard>()), Times.Once);

var mockRepo = new Mock<IWhiteboardRepository>();
var mockLsRepo = new Mock<ILearningSpaceRepository>();
var learningSpace = new LearningSpace("LS-001", 1.0, 1.0); // Small space
mockLsRepo.Setup(r => r.GetByIdAsync("LS-001")).ReturnsAsync(learningSpace);
var service = new WhiteboardService(mockRepo.Object, mockLsRepo.Object);

var result = await service.CreateWhiteboardAsync("WB-001", 5.0, 5.0, "LS-001");

Assert.That(result.IsSuccess, Is.False);
Assert.That(result.ErrorMessage, Does.Contain("doesn't fit"));
mockRepo.Verify(r => r.AddAsync(It.IsAny<Whiteboard>()), Times.Never);

