var options = new DbContextOptionsBuilder<UCRDatabaseContext>()
    .UseInMemoryDatabase(databaseName: "TestDb")
    .Options;
var context = new UCRDatabaseContext(options);
var repository = new WhiteboardRepository(context);
var whiteboard = new Whiteboard("WB-001", 2.0, 1.5);

await repository.AddAsync(whiteboard);
await context.SaveChangesAsync();

var saved = await context.Whiteboards.FindAsync("WB-001");
Assert.That(saved, Is.Not.Null);
Assert.That(saved.Id, Is.EqualTo("WB-001"));

var options = new DbContextOptionsBuilder<UCRDatabaseContext>()
    .UseInMemoryDatabase(databaseName: "TestDb")
    .Options;
var context = new UCRDatabaseContext(options);
var repository = new WhiteboardRepository(context);
var whiteboard = new Whiteboard("WB-001", 2.0, 1.5);
await repository.AddAsync(whiteboard);
await context.SaveChangesAsync();

var retrieved = await repository.GetByIdAsync("WB-001");

Assert.That(retrieved, Is.Not.Null);
Assert.That(retrieved.Id, Is.EqualTo("WB-001"));
Assert.That(retrieved.Width, Is.EqualTo(2.0));
Assert.That(retrieved.Height, Is.EqualTo(1.5));

var options = new DbContextOptionsBuilder<UCRDatabaseContext>()
    .UseInMemoryDatabase(databaseName: "TestDb")
    .Options;
var context = new UCRDatabaseContext(options);
var repository = new WhiteboardRepository(context);

var retrieved = await repository.GetByIdAsync("WB-999");

Assert.That(retrieved, Is.Null);

var mockService = new Mock<IWhiteboardService>();
var successResult = Result.Success();
mockService.Setup(s => s.CreateWhiteboardAsync("WB-001", 2.0, 1.5, "LS-001"))
    .ReturnsAsync(successResult);
var handler = new CreateWhiteboardHandler(mockService.Object);
var request = new CreateWhiteboardRequest("WB-001", 2.0, 1.5, "LS-001");

var result = await handler.HandleAsync(request);

Assert.That(result.StatusCode, Is.EqualTo(201));
Assert.That(result.Response.Success, Is.True);

var mockService = new Mock<IWhiteboardService>();
var failureResult = Result.Failure("Whiteboard doesn't fit in learning space");
mockService.Setup(s => s.CreateWhiteboardAsync("WB-001", 5.0, 5.0, "LS-001"))
    .ReturnsAsync(failureResult);
var handler = new CreateWhiteboardHandler(mockService.Object);
var request = new CreateWhiteboardRequest("WB-001", 5.0, 5.0, "LS-001");

var result = await handler.HandleAsync(request);

Assert.That(result.StatusCode, Is.EqualTo(400));
Assert.That(result.Response.Success, Is.False);
Assert.That(result.Response.ErrorMessage, Does.Contain("doesn't fit"));
